import{_ as t,o as i,c as s,ag as o}from"./chunks/framework.BBBcTwIo.js";const g=JSON.parse('{"title":"ILPP diagnostics and settings","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/ilpp-diagnostics.md","filePath":"how-to/ilpp-diagnostics.md"}'),a={name:"how-to/ilpp-diagnostics.md"};function n(r,e,l,d,c,p){return i(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="ilpp-diagnostics-and-settings" tabindex="-1">ILPP diagnostics and settings <a class="header-anchor" href="#ilpp-diagnostics-and-settings" aria-label="Permalink to &quot;ILPP diagnostics and settings&quot;">​</a></h1><p><strong>Goal:</strong> Confirm that the IL Post-Processor runs, control whether recording rewrites apply, and surface compile-time warnings.</p><p><strong>Prerequisites:</strong> Unity writes to <code>Library/</code> for your project; you can edit JSON or use the Event Monitor toolbar where available.</p><h2 id="settings-file" tabindex="-1">Settings file <a class="header-anchor" href="#settings-file" aria-label="Permalink to &quot;Settings file&quot;">​</a></h2><p>During compilation, ILPP reads:</p><p><code>Library/EventMonitor/ilpp_settings.json</code></p><p>If the file is missing or a key is absent, <strong>recording</strong> defaults to <strong>enabled</strong> (backward compatible).</p><table tabindex="0"><thead><tr><th>Key</th><th>Default</th><th>Meaning</th></tr></thead><tbody><tr><td><code>recordingEnabled</code></td><td><code>true</code></td><td>When <code>false</code>, the post-processor skips rewriting for that compile — no automatic SUB/UNSUB/INVOKE injection from ILPP.</td></tr><tr><td><code>ilppDiagnosticsEnabled</code></td><td><code>false</code></td><td>When <code>true</code>, emits <strong>Unity Console</strong> messages (warnings) summarizing ILPP activity, for example per-assembly SUB/UNSUB/INVOKE injection counts.</td></tr></tbody></table><p>Example:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;recordingEnabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;ilppDiagnosticsEnabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">EditorPrefs vs JSON</p><p>Toolbar toggles may sync settings into this JSON for ILPP (implementation-specific). If behavior disagrees with the file, check both the window and <code>Library/EventMonitor/ilpp_settings.json</code>.</p></div><h2 id="project-root-resolution" tabindex="-1">Project root resolution <a class="header-anchor" href="#project-root-resolution" aria-label="Permalink to &quot;Project root resolution&quot;">​</a></h2><p>ILPP discovers the project root from <strong>reference paths</strong> (for example paths containing <code>\\Library\\</code> or <code>/Library/</code>). If the file is never read, verify your Unity project layout and that compilation runs in a normal Editor context.</p><h2 id="when-to-enable-diagnostics" tabindex="-1">When to enable diagnostics <a class="header-anchor" href="#when-to-enable-diagnostics" aria-label="Permalink to &quot;When to enable diagnostics&quot;">​</a></h2><ul><li>After adding Event Monitor to a new project and seeing <strong>no INVOKE</strong> rows.</li><li>When migrating Unity or Cecil versions.</li><li>When debugging custom asmdef layout.</li></ul><p>Disable diagnostics again for quieter compiles once you are satisfied.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../reference/ilpp-settings.html">ILPP settings (JSON) reference</a></li><li><a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a></li></ul>`,18)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
